FUNCTION_BLOCK FB_CalculateDayOfYear
VAR_INPUT 
    Year : INT; 
    Month : INT; 
    Day : INT; 
END_VAR

VAR_OUTPUT 
    DayOfYear : INT; 
    error : BOOL; 
    status : WORD; 
END_VAR

VAR_TEMP
    i: INT;
    IsLeapYear: BOOL;
END_VAR

VAR
    DaysInMonth : ARRAY[1..12] OF INT := [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
END_VAR

// Initialize outputs
DayOfYear := 0;
error := FALSE;
status := 0;

// Input Validation
IF (Year < 1000) OR (Year > 3000) THEN
    error := TRUE;
    status := 16#8001; // Invalid year
    RETURN;
END_IF;

IF (Month < 1) OR (Month > 12) THEN
    error := TRUE;
    status := 16#8002; // Invalid month
    RETURN;
END_IF;

// Check for leap year
IsLeapYear := (Year MOD 4 = 0 AND Year MOD 100 <> 0) OR (Year MOD 400 = 0);
IF IsLeapYear THEN
    DaysInMonth[2] := 29; // Adjust February for leap year
ELSE
    DaysInMonth[2] := 28; // Standard February
END_IF;

// Validate day
IF (Day <= 0) OR (Day > DaysInMonth[Month]) THEN
    error := TRUE;
    status := 16#8003; // Invalid day
    RETURN;
END_IF;

// Calculate Day of Year
FOR i := 1 TO Month - 1 DO
    DayOfYear := DayOfYear + DaysInMonth[i]; // Sum days from completed months
END_FOR;

DayOfYear := DayOfYear + Day; // Add current day

// Add 1 day if after February in a leap year
IF (Month > 2) AND IsLeapYear THEN
    DayOfYear := DayOfYear + 1;
END_IF;

END_FUNCTION_BLOCK

