    error : BOOL := FALSE;
    status : WORD := 16#0000;
END_VAR_OUTPUT

VAR
    i, j, minIndex : INT;
    temp : VARIANT;
    isArray : BOOL := FALSE;
    arrayLength : INT;
END_VAR

// Check if the input seq is an array type
IF exe THEN
    // Attempt to determine if seq is an array
    isArray := (TypeOf(seq) = 'ARRAY');

    IF NOT isArray THEN
        error := TRUE;
        status := 16#8A01; // Invalid array type
    ELSE
        // Get the length of the array
        arrayLength := ArrayLength(seq);

        // Selection sort algorithm
        FOR i := 0 TO arrayLength - 2 DO
            minIndex := i;
            FOR j := i + 1 TO arrayLength - 1 DO
                IF seq[j] < seq[minIndex] THEN
                    minIndex := j;
                END_IF;
            END_FOR;
            // Swap the found minimum element with the first element
            IF minIndex <> i THEN
                temp := seq[i];
                seq[i] := seq[minIndex];
                seq[minIndex] := temp;
            END_IF;
        END_FOR;

        error := FALSE;
        status := 16#0000; // No error
    END_IF;
END_IF;

END_FUNCTION_BLOCK

