FUNCTION_BLOCK FloatingAverage
VAR_INPUT
    cyclicExecution : BOOL;
    trigger : BOOL;
    value : REAL;
    windowSize : INT;
    reset : BOOL;
END_VAR

VAR_OUTPUT
    average : REAL;
    windowSizeReached : BOOL;
    error : BOOL;
    status : WORD;
END_VAR

VAR
    dataBuffer : ARRAY[1..100] OF REAL; (* Buffer to store the data values *)
    bufferIndex : INT := 1; (* Index to track the current position in the buffer *)
    sum : REAL := 0.0; (* Sum of the data values in the buffer *)
    count : INT := 0; (* Count of valid data points in the buffer *)
END_VAR

(* Initialization *)
IF reset THEN
    average := 0.0;
    sum := 0.0;
    count := 0;
    bufferIndex := 1;
    windowSizeReached := FALSE;
    error := FALSE;
    status := 16#0000; (* Execution successful *)
ELSE
    (* Check window size validity *)
    IF windowSize < 1 OR windowSize > 100 THEN
        error := TRUE;
        status := 16#8200; (* Window length setting error *)
    ELSE
        error := FALSE;
        status := 16#0000; (* Execution successful *)

        (* Update moving average on cyclic execution or trigger *)
        IF cyclicExecution OR (trigger AND NOT trigger[1]) THEN
            (* Update buffer and sum *)
            IF count < windowSize THEN
                count := count + 1;
                sum := sum + value;
                dataBuffer[bufferIndex] := value;
                bufferIndex := bufferIndex MOD windowSize + 1; (* Circular buffer logic *)
            ELSE
                sum := sum - dataBuffer[bufferIndex] + value;
                dataBuffer[bufferIndex] := value;
                bufferIndex := bufferIndex MOD windowSize + 1; (* Circular buffer logic *)
            END_IF

            (* Calculate average *)
            average := sum / count;

            (* Check if window size has been reached *)
            IF count >= windowSize THEN
                windowSizeReached := TRUE;
            ELSE
                windowSizeReached := FALSE;
            END_IF
        END_IF
    END_IF
END_IF

END_FUNCTION_BLOCK

